<template>
  <div class="auth-field">
    <label class="auth-field__label">{{ label }}</label>
    <div class="auth-field__wrapper">
      <input
        :value="value"
        :type="computedType"
        :autocomplete="autocomplete"
        :placeholder="placeholder"
        class="auth-field__input"
        @input="$emit('input', $event.target.value)"
      />
      <button
        v-if="type === 'password'"
        type="button"
        class="auth-field__icon"
        @click="togglePassword"
      >
        <svg v-if="showPassword" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
          <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/>
          <circle cx="12" cy="12" r="3"/>
        </svg>
        <svg v-else width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
          <path d="M17.94 17.94A10.07 10.07 0 0112 20c-7 0-11-8-11-8a18.45 18.45 0 015.06-5.94M9.9 4.24A9.12 9.12 0 0112 4c7 0 11 8 11 8a18.5 18.5 0 01-2.16 3.19m-6.72-1.07a3 3 0 11-4.24-4.24"/>
          <line x1="1" y1="1" x2="23" y2="23"/>
        </svg>
      </button>
      <span v-else-if="type === 'email'" class="auth-field__icon auth-field__icon--static">
        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
          <rect x="2" y="4" width="20" height="16" rx="2"/>
          <path d="M22 4l-10 8L2 4"/>
        </svg>
      </span>
    </div>
    <p v-if="error" class="auth-field__error">{{ error }}</p>
  </div>
</template>

<script>
export default {
  name: 'AuthFormField',
  props: {
    value: { type: String, default: '' },
    type: { type: String, default: 'text' },
    label: { type: String, required: true },
    placeholder: { type: String, default: '' },
    error: { type: String, default: '' },
    autocomplete: { type: String, default: '' },
  },
  data() {
    return {
      showPassword: false,
    }
  },
  computed: {
    computedType() {
      if (this.type === 'password') {
        return this.showPassword ? 'text' : 'password'
      }
      return this.type
    },
  },
  methods: {
    togglePassword() {
      this.showPassword = !this.showPassword
    },
  },
}
</script>

